"""SVM via simplified gradient descent (linear kernel)."""
import numpy as np
from sklearn.base import BaseEstimator, ClassifierMixin


class SVC(BaseEstimator, ClassifierMixin):
    """Linear SVM classifier via SGD on hinge loss."""
    def __init__(self, *, C=1.0, kernel='linear', degree=3, gamma='scale',
                 coef0=0.0, shrinking=True, probability=False, tol=1e-3,
                 cache_size=200, class_weight=None, verbose=False,
                 max_iter=1000, decision_function_shape='ovr',
                 break_ties=False, random_state=None, lr=0.001):
        self.C = C
        self.kernel = kernel
        self.degree = degree
        self.gamma = gamma
        self.coef0 = coef0
        self.shrinking = shrinking
        self.probability = probability
        self.tol = tol
        self.cache_size = cache_size
        self.class_weight = class_weight
        self.verbose = verbose
        self.max_iter = max_iter
        self.decision_function_shape = decision_function_shape
        self.break_ties = break_ties
        self.random_state = random_state
        self.lr = lr
        self.classes_ = None
        self.coef_ = None
        self.intercept_ = None

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y)
        if X.ndim == 1: X = X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        n, p = X.shape
        if len(self.classes_) == 2:
            y_bin = np.where(y == self.classes_[1], 1.0, -1.0)
            w = np.zeros(p)
            b = 0.0
            rng = np.random.RandomState(self.random_state)
            for t in range(1, self.max_iter + 1):
                i = rng.randint(n)
                margin = y_bin[i] * (X[i] @ w + b)
                eta = self.lr / (1 + self.lr * t * 0.001)
                if margin < 1:
                    w = (1 - eta / self.C) * w + eta * y_bin[i] * X[i]
                    b += eta * y_bin[i]
                else:
                    w = (1 - eta / self.C) * w
            self.coef_ = w.reshape(1, -1)
            self.intercept_ = np.array([b])
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1: X = X.reshape(-1, 1)
        scores = X @ self.coef_[0] + self.intercept_[0]
        return np.where(scores >= 0, self.classes_[1], self.classes_[0])


class SVR(BaseEstimator):
    """Linear SVR (epsilon-insensitive loss)."""
    def __init__(self, *, kernel='rbf', degree=3, gamma='scale', coef0=0.0,
                 tol=1e-3, C=1.0, epsilon=0.1, shrinking=True,
                 cache_size=200, verbose=False, max_iter=1000, lr=0.001):
        self.kernel = kernel
        self.degree = degree
        self.gamma = gamma
        self.coef0 = coef0
        self.tol = tol
        self.C = C
        self.epsilon = epsilon
        self.shrinking = shrinking
        self.cache_size = cache_size
        self.verbose = verbose
        self.max_iter = max_iter
        self.lr = lr
        self.coef_ = None
        self.intercept_ = 0.0

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1: X = X.reshape(-1, 1)
        n, p = X.shape
        w = np.zeros(p)
        b = 0.0
        for t in range(1, self.max_iter + 1):
            i = t % n
            pred = X[i] @ w + b
            err = y[i] - pred
            eta = self.lr / (1 + self.lr * t * 0.001)
            if abs(err) > self.epsilon:
                grad = -np.sign(err)
                w -= eta * (grad * X[i] + w / (self.C * n))
                b -= eta * grad
            else:
                w *= (1 - eta / (self.C * n))
        self.coef_ = w
        self.intercept_ = b
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1: X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_


# ---------------------------------------------------------------------------
# LinearSVC
# ---------------------------------------------------------------------------

class LinearSVC(BaseEstimator, ClassifierMixin):
    """Linear Support Vector Classification (SGD on hinge/squared-hinge)."""

    def __init__(self, penalty='l2', loss='squared_hinge', *, dual='warn',
                 tol=1e-4, C=1.0, multi_class='ovr', fit_intercept=True,
                 intercept_scaling=1, class_weight=None, verbose=0,
                 random_state=None, max_iter=1000):
        self.penalty = penalty
        self.loss = loss
        self.dual = dual
        self.tol = tol
        self.C = C
        self.multi_class = multi_class
        self.fit_intercept = fit_intercept
        self.intercept_scaling = intercept_scaling
        self.class_weight = class_weight
        self.verbose = verbose
        self.random_state = random_state
        self.max_iter = max_iter
        self.classes_ = None
        self.coef_ = None
        self.intercept_ = None

    def _fit_binary(self, X, y_bin, rng):
        n, p = X.shape
        w = np.zeros(p)
        b = 0.0
        lr = 0.01
        for t in range(1, self.max_iter + 1):
            i = rng.randint(n)
            margin = y_bin[i] * (X[i] @ w + b)
            eta = lr / (1 + lr * t * 1e-4)
            if self.loss == 'squared_hinge':
                if margin < 1:
                    w = (1 - eta / self.C) * w + eta * 2 * (1 - margin) * y_bin[i] * X[i]
                    if self.fit_intercept:
                        b += eta * 2 * (1 - margin) * y_bin[i]
                else:
                    w *= (1 - eta / self.C)
            else:  # hinge
                if margin < 1:
                    w = (1 - eta / self.C) * w + eta * y_bin[i] * X[i]
                    if self.fit_intercept:
                        b += eta * y_bin[i]
                else:
                    w *= (1 - eta / self.C)
        return w, b

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        rng = np.random.RandomState(self.random_state)
        if len(self.classes_) == 2:
            y_bin = np.where(y == self.classes_[1], 1.0, -1.0)
            w, b = self._fit_binary(X, y_bin, rng)
            self.coef_ = w.reshape(1, -1)
            self.intercept_ = np.array([b])
        else:
            # One-vs-Rest
            coefs = []
            intercepts = []
            for c in self.classes_:
                y_bin = np.where(y == c, 1.0, -1.0)
                w, b = self._fit_binary(X, y_bin, rng)
                coefs.append(w)
                intercepts.append(b)
            self.coef_ = np.array(coefs)
            self.intercept_ = np.array(intercepts)
        return self

    def decision_function(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_.T + self.intercept_

    def predict(self, X):
        scores = self.decision_function(X)
        if len(self.classes_) == 2:
            return np.where(scores.ravel() >= 0, self.classes_[1], self.classes_[0])
        return self.classes_[np.argmax(scores, axis=1)]


# ---------------------------------------------------------------------------
# LinearSVR
# ---------------------------------------------------------------------------

class LinearSVR(BaseEstimator):
    """Linear Support Vector Regression."""

    def __init__(self, *, epsilon=0.0, tol=1e-4, C=1.0,
                 loss='epsilon_insensitive', fit_intercept=True,
                 intercept_scaling=1.0, dual='warn', verbose=0,
                 random_state=None, max_iter=1000):
        self.epsilon = epsilon
        self.tol = tol
        self.C = C
        self.loss = loss
        self.fit_intercept = fit_intercept
        self.intercept_scaling = intercept_scaling
        self.dual = dual
        self.verbose = verbose
        self.random_state = random_state
        self.max_iter = max_iter
        self.coef_ = None
        self.intercept_ = 0.0

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        w = np.zeros(p)
        b = 0.0
        rng = np.random.RandomState(self.random_state)
        lr = 0.01
        for t in range(1, self.max_iter + 1):
            i = rng.randint(n)
            pred = X[i] @ w + b
            err = y[i] - pred
            eta = lr / (1 + lr * t * 1e-4)
            if self.loss == 'squared_epsilon_insensitive':
                if abs(err) > self.epsilon:
                    grad = -2.0 * (err - np.sign(err) * self.epsilon)
                    w = (1 - eta / self.C) * w - eta * grad * X[i]
                    if self.fit_intercept:
                        b -= eta * grad
                else:
                    w *= (1 - eta / self.C)
            else:  # epsilon_insensitive
                if abs(err) > self.epsilon:
                    w = (1 - eta / self.C) * w + eta * np.sign(err) * X[i]
                    if self.fit_intercept:
                        b += eta * np.sign(err)
                else:
                    w *= (1 - eta / self.C)
        self.coef_ = w
        self.intercept_ = b
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_


# ---------------------------------------------------------------------------
# NuSVC
# ---------------------------------------------------------------------------

class NuSVC(BaseEstimator, ClassifierMixin):
    """Nu-Support Vector Classification.

    Uses nu parameter instead of C. Approximated via SGD.
    """

    def __init__(self, *, nu=0.5, kernel='rbf', degree=3, gamma='scale',
                 coef0=0.0, shrinking=True, probability=False, tol=1e-3,
                 cache_size=200, class_weight=None, verbose=False,
                 max_iter=-1, decision_function_shape='ovr',
                 break_ties=False, random_state=None):
        self.nu = nu
        self.kernel = kernel
        self.degree = degree
        self.gamma = gamma
        self.coef0 = coef0
        self.shrinking = shrinking
        self.probability = probability
        self.tol = tol
        self.cache_size = cache_size
        self.class_weight = class_weight
        self.verbose = verbose
        self.max_iter = max_iter if max_iter > 0 else 1000
        self.decision_function_shape = decision_function_shape
        self.break_ties = break_ties
        self.random_state = random_state
        self.classes_ = None
        self.coef_ = None
        self.intercept_ = None

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        self.classes_ = np.unique(y)
        n, p = X.shape
        rng = np.random.RandomState(self.random_state)
        # Convert nu to approximate C
        C = 1.0 / max(self.nu * n, 1)
        if len(self.classes_) == 2:
            y_bin = np.where(y == self.classes_[1], 1.0, -1.0)
            w = np.zeros(p)
            b = 0.0
            lr = 0.001
            for t in range(1, self.max_iter + 1):
                i = rng.randint(n)
                margin = y_bin[i] * (X[i] @ w + b)
                eta = lr / (1 + lr * t * 1e-4)
                if margin < 1:
                    w = (1 - eta / C) * w + eta * y_bin[i] * X[i]
                    b += eta * y_bin[i]
                else:
                    w *= (1 - eta / C)
            self.coef_ = w.reshape(1, -1)
            self.intercept_ = np.array([b])
        else:
            coefs, intercepts = [], []
            for c in self.classes_:
                y_bin = np.where(y == c, 1.0, -1.0)
                w = np.zeros(p)
                b = 0.0
                lr = 0.001
                for t in range(1, self.max_iter + 1):
                    i = rng.randint(n)
                    margin = y_bin[i] * (X[i] @ w + b)
                    eta = lr / (1 + lr * t * 1e-4)
                    if margin < 1:
                        w = (1 - eta / C) * w + eta * y_bin[i] * X[i]
                        b += eta * y_bin[i]
                    else:
                        w *= (1 - eta / C)
                coefs.append(w)
                intercepts.append(b)
            self.coef_ = np.array(coefs)
            self.intercept_ = np.array(intercepts)
        return self

    def decision_function(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_.T + self.intercept_

    def predict(self, X):
        scores = self.decision_function(X)
        if len(self.classes_) == 2:
            return np.where(scores.ravel() >= 0, self.classes_[1], self.classes_[0])
        return self.classes_[np.argmax(scores, axis=1)]


# ---------------------------------------------------------------------------
# NuSVR
# ---------------------------------------------------------------------------

class NuSVR(BaseEstimator):
    """Nu-Support Vector Regression."""

    def __init__(self, *, nu=0.5, C=1.0, kernel='rbf', degree=3,
                 gamma='scale', coef0=0.0, shrinking=True, tol=1e-3,
                 cache_size=200, verbose=False, max_iter=-1):
        self.nu = nu
        self.C = C
        self.kernel = kernel
        self.degree = degree
        self.gamma = gamma
        self.coef0 = coef0
        self.shrinking = shrinking
        self.tol = tol
        self.cache_size = cache_size
        self.verbose = verbose
        self.max_iter = max_iter if max_iter > 0 else 1000
        self.coef_ = None
        self.intercept_ = 0.0

    def fit(self, X, y):
        X = np.asarray(X, dtype=float)
        y = np.asarray(y, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        # Epsilon derived from nu
        epsilon = self.nu * (y.max() - y.min()) / 2.0
        w = np.zeros(p)
        b = 0.0
        lr = 0.001
        for t in range(1, self.max_iter + 1):
            i = t % n
            pred = X[i] @ w + b
            err = y[i] - pred
            eta = lr / (1 + lr * t * 1e-4)
            if abs(err) > epsilon:
                w -= eta * (-np.sign(err) * X[i] + w / (self.C * n))
                b += eta * np.sign(err)
            else:
                w *= (1 - eta / (self.C * n))
        self.coef_ = w
        self.intercept_ = b
        return self

    def predict(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_


# ---------------------------------------------------------------------------
# OneClassSVM
# ---------------------------------------------------------------------------

class OneClassSVM(BaseEstimator):
    """Unsupervised outlier detection via One-Class SVM.

    Learns a hyperplane that separates the training data from the origin
    in feature space. Uses linear kernel approximation via SGD.
    """

    def __init__(self, *, kernel='rbf', degree=3, gamma='scale', coef0=0.0,
                 tol=1e-3, nu=0.5, shrinking=True, cache_size=200,
                 verbose=False, max_iter=-1):
        self.kernel = kernel
        self.degree = degree
        self.gamma = gamma
        self.coef0 = coef0
        self.tol = tol
        self.nu = nu
        self.shrinking = shrinking
        self.cache_size = cache_size
        self.verbose = verbose
        self.max_iter = max_iter if max_iter > 0 else 1000
        self.coef_ = None
        self.intercept_ = 0.0

    def fit(self, X, y=None, sample_weight=None):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        n, p = X.shape
        rng = np.random.RandomState(42)
        w = np.zeros(p)
        b = 0.0
        C = 1.0 / (self.nu * n)
        lr = 0.001
        # All samples are "positive" (label +1) in one-class SVM
        for t in range(1, self.max_iter + 1):
            i = rng.randint(n)
            margin = X[i] @ w + b
            eta = lr / (1 + lr * t * 1e-4)
            if margin < 1:
                w = (1 - eta / C) * w + eta * X[i]
                b += eta
            else:
                w *= (1 - eta / C)
        self.coef_ = w
        self.intercept_ = b
        # Compute offset so that nu fraction of points are outliers
        scores = X @ self.coef_ + self.intercept_
        self.offset_ = np.percentile(scores, 100.0 * self.nu)
        return self

    def decision_function(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_ - self.offset_

    def predict(self, X):
        scores = self.decision_function(X)
        return np.where(scores >= 0, 1, -1)

    def score_samples(self, X):
        X = np.asarray(X, dtype=float)
        if X.ndim == 1:
            X = X.reshape(-1, 1)
        return X @ self.coef_ + self.intercept_
